    elif cmd == "tally":
        print(f"Signatures for {sys.argv[2]}: {tally(sys.argv[2])}")
    elif cmd == "invoke":
        h = sys.argv[2]
        ctx = json.loads(sys.argv[3]) if len(sys.argv) > 3 else {}
        print(json.dumps(invoke(h, ctx), indent=2))
    elif cmd == "mcp":
