    l2_h = manifest.get("capabilities", {}).get("librarian", {}).get("stable")
    if not l2_h or h == l2_h: return _raw_get(h, is_bios=True)
    try:
        l2_payload = _raw_get(l2_h, is_bios=True)
        l2_scope = {"context": {"target": h, "vault_tiers": ["blob_vault", "remote_vault", "collective_vault"]}, "log": lambda m: None, "result": None, "embed": embed, "rerank": rerank, "inference": inference, "json": json, "os": os, "glob": glob}
        exec(l2_payload, l2_scope, l2_scope)
        resolved_path = l2_scope.get("result", {}).get("path")
        if resolved_path and os.path.exists(resolved_path):
            with open(resolved_path, "r") as f: return f.read()
    except Exception: pass
    return _raw_get(h, is_bios=True)

def put(payload: str, blob_type: str = "generic") -> str:
    h = hashlib.sha256(payload.encode()).hexdigest()
    path = VAULT_DIR / h
    with open(path, 'w') as f: f.write(payload)
